  5	import InfoCircleIcon from '@patternfly/react-icons/dist/esm/icons/info-circle-icon';
  6	import cn from 'classnames';
  7	import { useController, Control, FieldValues } from 'react-hook-form';
  8	import {
  9	  FormGroup,
 10	  FormGroupProps,
 11	  InputGroup,
 12	  TextInput,
 13	  Tooltip,
 14	  Button,
 15	  Popover,
 16	  PopoverProps,
 17	  PopoverPosition,
 18	  HelperText,
 19	  HelperTextItem,
 20	  TextInputProps,
 21	  Icon,
 22	  FormHelperText,
 23	  HelperTextItemProps,
 24	} from '@patternfly/react-core';
 25	import { EyeSlashIcon, EyeIcon } from '@patternfly/react-icons';
 26	import useFieldRequirements from '../input-with-requirements/useFieldRequirements';
 27	import { useCustomTranslation } from '../useCustomTranslationHook';
 28	import '../input-with-requirements/TextInputWithFieldRequirements.scss';
 29	
 30	type PasswordInputProps = {
 31	  id: string;
 32	  value: string;
 33	  onChange: (value: string) => void;
 34	  isRequired?: boolean;
 35	  placeholder?: string;
 36	};
 37	
 38	const PasswordInput: React.FC<PasswordInputProps> = ({
 39	  id,
 40	  value,
 41	  onChange,
 42	  isRequired,
 43	  placeholder,
 44	}) => {
 45	  const { t } = useCustomTranslation();
 46	  const [showPassword, setShowPassword] = React.useState(false);
 47	
 48	  return (
 49	    <InputGroup>
 50	      <TextInput
 51	        id={id}
 52	        type={showPassword ? 'text' : 'password'}
 53	        value={value}
 54	        onChange={(_event, newValue) => onChange(newValue)}
 55	        isRequired={isRequired}
 56	        placeholder={placeholder}
 57	      />
 58	      <Tooltip content={showPassword ? t('Hide password') : t('Show password')}>
 59	        <Button
 60	          variant="control"
 61	          onClick={() => setShowPassword(!showPassword)}
 62	        >
 63	          {showPassword ? <EyeSlashIcon /> : <EyeIcon />}
 64	        </Button>
 65	      </Tooltip>
 66	    </InputGroup>
 67	  );
 68	};
 69	
 70	export type ValidatedPasswordInputProps = {
 71	  fieldRequirements: string[];
 72	  control: Control<FieldValues>;
 73	  defaultValue?: any;
 74	  formGroupProps: FormGroupProps;
 75	  // In PF5 FormGroupProps don't have helperText
 76	  helperText?: string;
 77	  textInputProps: TextInputProps & {
 78	    'data-test': string;
 79	    disabled?: boolean;
 80	  };
 81	  popoverProps: Omit<PopoverProps, 'bodyContent'>;
 82	  infoElement?: JSX.Element;
 83	  inputPrefixElement?: JSX.Element;
 84	};
 85	
 86	export const getStatusIcon = (status: string) => {
 87	  switch (status) {
 88	    case 'error':
 89	      return <ExclamationCircleIcon />;
 90	    case 'success':
 91	      return <CheckCircleIcon />;
 92	    default:
 93	      return <InfoCircleIcon />;
 94	  }
 95	};
 96	
 97	const getVariant = (status: string) => {
 98	  switch (status) {
 99	    case 'error':
100	      return 'danger';
101	    case 'success':
102	      return 'success';
103	    default:
104	      return 'info';
105	  }
106	};
107	
108	const ValidatedPasswordInput: React.FC<ValidatedPasswordInputProps> = ({
109	  fieldRequirements,
110	  control,
111	  formGroupProps,
112	  textInputProps,
113	  popoverProps,
114	  defaultValue = '',
115	  helperText,
116	  infoElement,
117	  inputPrefixElement,
118	}) => {
119	  const { t } = useCustomTranslation();
120	  const [showPassword, setShowPassword] = React.useState(false);
121	  const {
122	    field: { name, value, onChange, onBlur },
123	    fieldState: { error, isDirty, isTouched },
124	    formState: { isSubmitted },
125	  } = useController({
126	    name: textInputProps.name || 'name',
127	    control,
128	    defaultValue: defaultValue,
129	  });
130	  const state = useFieldRequirements(
131	    fieldRequirements,
132	    isDirty || isSubmitted,
133	    error
134	  );
135	  const [isVisible, setIsVisible] = React.useState(false);
136	  const [validated, setValidated] =
137	    React.useState<HelperTextItemProps['variant']>('default');
138	
139	  React.useEffect(() => {
140	    setValidated(
141	      isDirty || isTouched || isSubmitted
142	        ? error
143	          ? 'error'
144	          : 'success'
145	        : 'default'
146	    );
147	  }, [error, isDirty, isTouched, isSubmitted]);
148	
149	  const handleInputChange = React.useCallback(
150	    (event: React.FormEvent<HTMLInputElement>, newValue: string) => {
151	      if (!isVisible) setIsVisible(true);
152	      textInputProps?.onChange?.(event, newValue);
153	      onChange(newValue, event);
154	    },
155	    [isVisible, onChange, textInputProps]
156	  );
157	
158	  const handleInputBlur = React.useCallback(
159	    (event: React.FormEvent<HTMLInputElement>) => {
160	      setIsVisible(false);
161	      textInputProps?.onBlur?.(event);
162	      onBlur();
163	    },
164	    [onBlur, textInputProps]
165	  );
166	
167	  return (
168	    <FormGroup {...formGroupProps}>
169	      {infoElement}
170	      <div className="field-requirements-input-section">
171	        {inputPrefixElement}
172	        <InputGroup
173	          data-test="field-requirements-input-group"
174	          className={cn(
175	            'rich-input__group',
176	            error && 'rich-input__group--invalid',
177	            !error && (isDirty || isSubmitted) && 'rich-input__group--success'
178	          )}
179	        >
180	          <InputGroupItem isFill>
181	            <TextInput
182	              {...textInputProps}
183	              name={name}
184	              type={showPassword ? 'text' : 'password'}
185	              value={value}
186	              className={cn('rich-input__text', textInputProps?.className)}
187	              onBlur={handleInputBlur}
188	              onFocus={() => setIsVisible(true)}
189	              onClick={() => setIsVisible(true)}
190	              onChange={handleInputChange}
191	              onKeyUp={onBlur /*Required for avoiding outdated validations.*/}
192	            />
193	          </InputGroupItem>
194	          <InputGroupItem>
195	            <Tooltip
196	              content={showPassword ? t('Hide password') : t('Show password')}
197	            >
198	              <Button
199	                variant="control"
200	                onClick={() => setShowPassword(!showPassword)}
201	                aria-label={
202	                  showPassword ? t('Hide password') : t('Show password')
203	                }
204	              >
205	                {showPassword ? <EyeSlashIcon /> : <EyeIcon />}
206	              </Button>
207	            </Tooltip>
208	          </InputGroupItem>
209	          <InputGroupItem>
210	            <Popover
211	              data-test="field-requirements-popover"
212	              position={PopoverPosition.top}
213	              isVisible={isVisible}
214	              shouldOpen={() => setIsVisible(true)}
215	              shouldClose={() => setIsVisible(false)}
216	              bodyContent={
217	                <HelperText component="ul">
218	                  {Object.keys(state.fieldRequirements).map((rule) => {
219	                    return (
220	                      <HelperTextItem
221	
222	                        variant={state.fieldRequirements[rule]}
223	                        component="li"
224	                        key={rule}
225	                      >
226	                        {rule}
227	                      </HelperTextItem>
228	                    );
229	                  })}
230	                </HelperText>
231	              }
232	              withFocusTrap={false}
233	              {...popoverProps}
234	            >
235	              <Button variant="plain" aria-label="Validation" tabIndex={-1}>
236	                <Icon status={getVariant(validated)}>
237	                  {getStatusIcon(validated)}
238	                </Icon>
239	              </Button>
240	            </Popover>
241	          </InputGroupItem>
242	        </InputGroup>
243	      </div>
244	      <FormHelperText>
245	        <HelperText>
246	          <HelperTextItem variant={validated}>{helperText}</HelperTextItem>
247	        </HelperText>
248	      </FormHelperText>
249	    </FormGroup>
250	  );
251	};
252	
253	export default PasswordInput;
254	export { ValidatedPasswordInput };

